script:
frappe.ui.form.on('HD Ticket', {
    refresh(frm) {
        if (frm.is_new()) return;

        frm.add_custom_button('Create a new sub-task', () => {
            frappe.new_doc('Task', {
                subject: 'متابعة: ' + frm.doc.subject,
                custom_ticket: frm.doc.name,
                description: 'مرتبطة بالتذكرة: ' + frm.doc.name
            });
        });

        frappe.db.get_list('Task', {
            filters: { custom_ticket: frm.doc.name, status: ['!=', 'Cancelled'] },
            fields: ['name', 'subject', 'status']
        }).then(tasks => {
            if (tasks.length > 0) {
                let html = '<table class="table table-bordered table-sm" style="margin-top:8px">';
                html += '<thead><tr><th>المهمة</th><th>الموضوع</th><th>الحالة</th></tr></thead><tbody>';
                tasks.forEach(t => {
                    html += `<tr>
                        <td><a href="/desk/Form/Task/${t.name}" target="_blank">${t.name}</a></td>
                        <td>${t.subject}</td>
                        <td>${t.status}</td>
                    </tr>`;
                });
                html += '</tbody></table>';
                frm.dashboard.add_section(html, 'المهام المرتبطة');
            }
        });
    }
});
